            for (&p, indices) in prime_to_indices.iter_mut() {
                if temp % p == 0 {
                    indices.push(j);
                }
            }
        }
    }

    let mut visited = vec![false; n];
    let mut queue = VecDeque::new();
    queue.push_back((0, 0));
    visited[0] = true;

    while let Some((current, steps)) = queue.pop_front() {
        if current == n - 1 {
            return steps;
